FUNCTION_BLOCK FB_CalculateDayOfYear
VAR_INPUT 
    Year : INT; 
    Month : INT; 
    Day : INT; 
END_VAR

VAR_OUTPUT 
    DayOfYear : INT; 
    error : BOOL; 
    status : WORD; 
END_VAR

VAR_TEMP
    i: INT;
    isLeapYear: BOOL;
    maxDaysInMonth: INT;
END_VAR

VAR
    DaysInMonth : ARRAY[1..12] OF INT := [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
END_VAR

// Initialize outputs
DayOfYear := 0;
error := FALSE;
status := 0;

// 1. Month validation (highest priority)
IF (Month < 1) OR (Month > 12) THEN
    error := TRUE;
    status := 16#8002;  // Invalid month
    RETURN;
END_IF;

// 2. Day validation (second priority)
// Check if day is positive
IF Day <= 0 THEN
    error := TRUE;
    status := 16#8003;  // Invalid day
    RETURN;
END_IF;

// Determine maximum days for the given month
maxDaysInMonth := DaysInMonth[Month];

// Check for leap year if February
IF Month = 2 THEN
    // Leap year calculation
    isLeapYear := ((Year MOD 4 = 0) AND (Year MOD 100 <> 0)) OR (Year MOD 400 = 0);

    IF isLeapYear THEN
        maxDaysInMonth := 29;
    ELSE
        maxDaysInMonth := 28;
    END_IF;
END_IF;

// Check if day exceeds maximum for the month
IF Day > maxDaysInMonth THEN
    error := TRUE;
    status := 16#8003;  // Invalid day
    RETURN;
END_IF;

// 3. Year validation (lowest priority)
IF (Year < 1000) OR (Year > 3000) THEN
    error := TRUE;
    status := 16#8001;  // Invalid year
    RETURN;
END_IF;

// All inputs are valid - calculate day of year
// Sum days from previous months
FOR i := 1 TO Month-1 DO
    DayOfYear := DayOfYear + DaysInMonth[i];
END_FOR;

// Add current day
DayOfYear := DayOfYear + Day;

// Add extra day for leap year if after February
IF Month > 2 THEN
    // Recalculate leap year (already calculated for February case)
    isLeapYear := ((Year MOD 4 = 0) AND (Year MOD 100 <> 0)) OR (Year MOD 400 = 0);

    IF isLeapYear THEN
        DayOfYear := DayOfYear + 1;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK SelectSort
VAR_INPUT
    exe : BOOL;
    seq : VARIANT;
END_VAR
VAR_OUTPUT
    error : BOOL;
    status : WORD;
END_VAR
VAR
    bExePrev : BOOL;
    nArraySize : DINT;
    i : DINT;
    j : DINT;
    minIndex : DINT;
    tempVar : VARIANT;
    bIsArray : BOOL;
    bTypeMatch : BOOL;
END_VAR

// Initialize outputs
error := TRUE;
status := 16#8A01; // Default to invalid array type

// Check for rising edge of exe
IF exe AND NOT bExePrev THEN
    // Reset error status initially
    error := TRUE;
    status := 16#8A01;

    // Check if variant contains an array
    bIsArray := __ISVARIANT(seq) AND __QUERYVARIANT(seq, '.IS_ARRAY');

    IF bIsArray THEN
        // Get array size
        nArraySize := __QUERYVARIANT(seq, '.SIZE');

        // Only sort if array has more than 1 element
        IF nArraySize > 1 THEN
            // Selection sort algorithm
            FOR i := 0 TO nArraySize - 2 DO
                minIndex := i;

                FOR j := i + 1 TO nArraySize - 1 DO
                    // Compare elements at positions j and minIndex
                    IF __QUERYVARIANT(seq, '[' + DINT_TO_STRING(j) + ']') < 
                       __QUERYVARIANT(seq, '[' + DINT_TO_STRING(minIndex) + ']') THEN
                        minIndex := j;
                    END_IF;
                END_FOR;

                // Swap elements if needed
                IF minIndex <> i THEN
                    // Store element at i in temp
                    __VARIANTTOVARIANT(__QUERYVARIANT(seq, '[' + DINT_TO_STRING(i) + ']'), tempVar);

                    // Copy element at minIndex to position i
                    __WRITEVARIANT(seq, '[' + DINT_TO_STRING(i) + ']', 
                                  __QUERYVARIANT(seq, '[' + DINT_TO_STRING(minIndex) + ']'));

                    // Copy temp to position minIndex
                    __WRITEVARIANT(seq, '[' + DINT_TO_STRING(minIndex) + ']', tempVar);
                END_IF;
            END_FOR;

            // Success
            error := FALSE;
            status := 16#0000;
        ELSIF nArraySize = 1 THEN
            // Single element array is already sorted
            error := FALSE;
            status := 16#0000;
        ELSE
            // Empty array is already sorted
            error := FALSE;
            status := 16#0000;
        END_IF;
    ELSE
        // Not an array type
        error := TRUE;
        status := 16#8A01;
    END_IF;
END_IF;

// Store previous exe state for edge detection
bExePrev := exe;
END_FUNCTION_BLOCK

