VAR_OUTPUT
    error : BOOL;
    status : WORD;
    randomNumber : DINT;
END_VAR

VAR
    internalSeed : DINT;
END_VAR

// Main execution logic
IF minValue > maxValue THEN
    // Range error handling
    error := TRUE;
    status := 16#8200;
    randomNumber := 0;
ELSE
    // Ensure seed is positive using absolute value
    internalSeed := ABS(randomSeed_in);

    // Generate random number using modulo arithmetic
    // Formula: randomNumber = minValue + (internalSeed MOD (maxValue - minValue + 1))
    randomNumber := minValue + (internalSeed MOD (maxValue - minValue + 1));

    // Set success status
    error := FALSE;
    status := 16#0000;
END_IF
END_FUNCTION_BLOCK

FUNCTION_BLOCK AnalogBatchConverter
VAR_INPUT
    count : INT; (* Number of channels to process (1..10) *)
    analogValues : ARRAY[1..10] OF REAL; (* Raw ADC values *)
END_VAR

VAR_IN_OUT
    channel_enable : ARRAY[1..10] OF BOOL; (* Enable conversion per channel *)
    channel_hiLIM : ARRAY[1..10] OF REAL; (* Upper scaling limit *)
    channel_loLIM : ARRAY[1..10] OF REAL; (* Lower scaling limit *)
    channel_bipolar : ARRAY[1..10] OF BOOL; (* FALSE=Unipolar, TRUE=Bipolar *)
    channel_measuringMode : ARRAY[1..10] OF INT; (* 0=Non-temp, 1=Std temp, 2=Climatic temp *)
END_VAR

VAR_OUTPUT
    channel_retVal : ARRAY[1..10] OF WORD; (* Status/error codes *)
    channel_outputValue : ARRAY[1..10] OF REAL; (* Converted output values *)
END_VAR

VAR
    i : INT; (* Loop counter *)
    rawValue : REAL; (* Temporary raw value storage *)
    scaleFactor : REAL; (* Temporary scaling factor *)
END_VAR

METHOD ProcessChannels
    (* Process each channel up to the specified count *)
    FOR i := 1 TO count DO
        (* Reset status and output for this channel *)
        channel_retVal[i] := 16#0000;
        channel_outputValue[i] := 0.0;

        (* Skip if channel not enabled *)
        IF NOT channel_enable[i] THEN
            CONTINUE;
        END_IF;

        (* Error Check 1: Invalid measuring mode *)
        IF (channel_measuringMode[i] < 0) OR (channel_measuringMode[i] > 2) THEN
            channel_retVal[i] := 16#8001;
            CONTINUE;
        END_IF;

        (* Error Check 2: Invalid scaling limits *)
        IF channel_hiLIM[i] <= channel_loLIM[i] THEN
            channel_retVal[i] := 16#8002;
            CONTINUE;
        END_IF;

        (* Get raw analog value *)
        rawValue := analogValues[i];

        (* Process based on measuring mode *)
        CASE channel_measuringMode[i] OF
            0: (* Non-temperature measurement *)
                IF channel_bipolar[i] THEN
                    (* Bipolar scaling: -27648.0 to 27648.0 -> loLIM to hiLIM *)
                    rawValue := LIMIT(-27648.0, rawValue, 27648.0);
                    scaleFactor := (channel_hiLIM[i] - channel_loLIM[i]) / 55296.0;
                    channel_outputValue[i] := channel_loLIM[i] + (rawValue + 27648.0) * scaleFactor;
                ELSE
                    (* Unipolar scaling: 0.0 to 27648.0 -> loLIM to hiLIM *)
                    rawValue := LIMIT(0.0, rawValue, 27648.0);
                    scaleFactor := (channel_hiLIM[i] - channel_loLIM[i]) / 27648.0;
                    channel_outputValue[i] := channel_loLIM[i] + rawValue * scaleFactor;
                END_IF;

            1: (* Standard temperature measurement *)
                channel_outputValue[i] := rawValue / 10.0;

            2: (* Climatic temperature measurement *)
                channel_outputValue[i] := rawValue / 100.0;
        END_CASE;
    END_FOR;
END_METHOD

(* Main execution *)
ProcessChannels();
END_FUNCTION_BLOCK

