    (* Error condition - Input out of range *)
    error := TRUE;
    status := 16#8001;

    (* Reset all outputs *)
    Thousands := 0;
    Hundreds := 0;
    Tens := 0;
    Ones := 0;
    Min := 0;
ELSE
    (* Valid input - proceed with processing *)
    error := FALSE;
    status := 16#0000;

    (* Digit Separation *)
    Thousands := InputNumber / 1000;
    tempNumber := InputNumber MOD 1000;
    Hundreds := tempNumber / 100;
    tempNumber := tempNumber MOD 100;
    Tens := tempNumber / 10;
    Ones := tempNumber MOD 10;

    (* Minimum non-zero digit detection *)
    minValue := 32767; (* Maximum INT value *)

    (* Check Thousands digit *)
    IF Thousands > 0 THEN
        minValue := minimal(minValue, Thousands);
    END_IF;

    (* Check Hundreds digit *)
    IF Hundreds > 0 THEN
        minValue := minimal(minValue, Hundreds);
    END_IF;

    (* Check Tens digit *)
    IF Tens > 0 THEN
        minValue := minimal(minValue, Tens);
    END_IF;

    (* Check Ones digit *)
    IF Ones > 0 THEN
        minValue := minimal(minValue, Ones);
    END_IF;

    (* Set Min output *)
    IF minValue = 32767 THEN
        (* All digits are zero *)
        Min := 0;
    ELSE
        Min := minValue;
    END_IF;
END_IF;
