FUNCTION_BLOCK ShellSortFixed
VAR_INPUT
    sortDirection : BOOL; (* FALSE = Ascending, TRUE = Descending *)
    arr : ARRAY[1..1000] OF DINT;
END_VAR

VAR_OUTPUT
    error : BOOL;
    status : WORD;
    sorted_arr : ARRAY[1..1000] OF DINT;
END_VAR

VAR
    gap : DINT;
    i : DINT;
    j : DINT;
    temp : DINT;
    n : DINT := 1000; (* Fixed array size *)
    swapped : BOOL;
END_VAR

(* Initialize outputs *)
error := FALSE;
status := 16#0000;

(* Copy input array to output array *)
FOR i := 1 TO n DO
    sorted_arr[i] := arr[i];
END_FOR;

(* Validate array size *)
IF n <= 1 THEN
    error := TRUE;
    status := 16#8200;
    RETURN;
ELSIF n > 1000 THEN
    error := TRUE;
    status := 16#8201;
    RETURN;
END_IF;

(* Shell Sort implementation *)
gap := n / 2;
WHILE gap > 0 DO
    i := gap + 1;
    WHILE i <= n DO
        temp := sorted_arr[i];
        j := i;

        IF NOT sortDirection THEN (* Ascending sort *)
            WHILE (j > gap) AND (sorted_arr[j - gap] > temp) DO
                sorted_arr[j] := sorted_arr[j - gap];
                j := j - gap;
            END_WHILE;
        ELSE (* Descending sort *)
            WHILE (j > gap) AND (sorted_arr[j - gap] < temp) DO
                sorted_arr[j] := sorted_arr[j - gap];
                j := j - gap;
            END_WHILE;
        END_IF;

        sorted_arr[j] := temp;
        i := i + 1;
    END_WHILE;

    gap := gap / 2;
END_WHILE;

(* Set success status *)
error := FALSE;
status := 16#0000;

FUNCTION_BLOCK FloatingAverage
VAR_INPUT
    cyclicExecution : BOOL;     (* When TRUE, periodic reading is performed, and trigger has no effect *)
    trigger : BOOL;             (* External trigger signal, reads value upon each rising edge *)
    value : REAL;               (* Newly read data value *)
    windowSize : INT;           (* The window size for the moving average, which must be between 1 and 100 *)
    reset : BOOL;               (* Reset signal, resets the moving average calculation when TRUE *)
END_VAR
VAR_OUTPUT
    average : REAL;             (* The moving average *)
    windowSizeReached : BOOL;   (* FALSE: Maximum window width not yet reached, TRUE: Maximum window width has been reached *)
    error : BOOL;               (* FALSE: No error occurred, TRUE: An error occurred during the execution of FB *)
    status : WORD;              (* Status code *)
END_VAR
VAR
    dataBuffer : ARRAY[1..100] OF REAL; (* Buffer to store the data values *)
    bufferIndex : INT := 1;     (* Index to track the current position in the buffer *)
    sum : REAL := 0.0;          (* Sum of the data values in the buffer *)
    dataCount : INT := 0;       (* Number of valid data points in buffer *)
    triggerPrev : BOOL := FALSE;(* Previous trigger state for edge detection *)
END_VAR

(* Main execution logic *)
IF reset THEN
    (* Reset all internal variables *)
    bufferIndex := 1;
    sum := 0.0;
    dataCount := 0;
    average := 0.0;
    windowSizeReached := FALSE;
    error := FALSE;
    status := 16#0000;

    (* Clear buffer *)
    FOR i := 1 TO 100 DO
        dataBuffer[i] := 0.0;
    END_FOR;

ELSIF (windowSize < 1) OR (windowSize > 100) THEN
    (* Window size error *)
    error := TRUE;
    status := 16#8200;

ELSE
    (* Check if we should process new data *)
    IF cyclicExecution OR (trigger AND NOT triggerPrev) THEN
        (* Update buffer with new value *)
        IF dataCount < windowSize THEN
            (* Buffer not full yet - add new value *)
            dataBuffer[bufferIndex] := value;
            sum := sum + value;
            dataCount := dataCount + 1;
        ELSE
            (* Buffer full - replace oldest value *)
            sum := sum - dataBuffer[bufferIndex] + value;
            dataBuffer[bufferIndex] := value;
        END_IF;

        (* Calculate average *)
        IF dataCount > 0 THEN
            average := sum / dataCount;
        ELSE
            average := 0.0;
        END_IF;

        (* Update window size reached flag *)
        windowSizeReached := (dataCount >= windowSize);

        (* Update buffer index *)
        bufferIndex := bufferIndex + 1;
        IF bufferIndex > windowSize THEN
            bufferIndex := 1;
        END_IF;

        (* Clear error and set success status *)
        error := FALSE;
        status := 16#0000;
    END_IF;
END_IF;

(* Store previous trigger state for edge detection *)
triggerPrev := trigger;

END_FUNCTION_BLOCK

query:
Bottle Processing Control System

###Instruction

Purpose:
Implement a function blocks (FB_BottleProcessing) implementing a sequential control system for bottle processing with five stages: cleaning, filling, capping, packing, and completion.

Input Variables:
- bottleSensor: BOOL - Detects presence of bottle
- cleaningConfirmButton: BOOL - Confirms cleaning stage completion
- fillingConfirmButton: BOOL - Confirms filling stage completion
- cappingConfirmButton: BOOL - Confirms capping stage completion
- packingConfirmButton: BOOL - Confirms packing stage completion
- finishedButton: BOOL - Confirms process completion

Output Variables:
- Pump_Motor: BOOL - Controls cleaning pump
- Filling_Valve: BOOL - Controls filling mechanism
- Capping_Machine: BOOL - Controls bottle capping
- Packing_Machine: BOOL - Controls packing system
- Completion_Light: BOOL - Indicates process completion

Internal Variables:
- State: INT - Controls process flow (Initialize to 0)
States: 0=Waiting, 1=Cleaning, 2=Filling, 3=Capping, 4=Packing, 5=Completed

Implementation Requirements:
1. State 0 (Waiting):
- When bottleSensor activates, start Pump_Motor and transition to State 1

2. State 1 (Cleaning):
- When cleaningConfirmButton activates:
 * Stop Pump_Motor
 * Start Filling_Valve
 * Transition to State 2

3. State 2 (Filling):
- When fillingConfirmButton activates:
 * Stop Filling_Valve
 * Start Capping_Machine
 * Transition to State 3

4. State 3 (Capping):
- When cappingConfirmButton activates:
 * Stop Capping_Machine
 * Start Packing_Machine
 * Transition to State 4

5. State 4 (Packing):
- When packingConfirmButton activates:
 * Stop Packing_Machine
 * Turn on Completion_Light
 * Transition to State 5

6. State 5 (Completed):
- When finishedButton activates:
 * Turn off Completion_Light
 * Reset all outputs to FALSE
 * Return to State 0

Note: Each state transition should occur only after receiving the corresponding confirmation signal, ensuring proper sequential operation.


FUNCTION_BLOCK FB_BottleProcessing

VAR_INPUT 
bottleSensor : BOOL;
cleaningConfirmButton : BOOL;
fillingConfirmButton : BOOL;
cappingConfirmButton : BOOL;
packingConfirmButton : BOOL;
finishedButton : BOOL;
END_VAR

VAR_OUTPUT 
Pump_Motor : BOOL;
Filling_Valve : BOOL;
Capping_Machine : BOOL;
Packing_Machine : BOOL;
Completion_Light : BOOL;
END_VAR

VAR 
State : INT := 0; (* 0: 等待瓶子, 1: 清洗, 2: 灌装, 3: 封盖, 4: 包装, 5: 完成 *)
END_VAR


CASE State OF
0: (* 等待瓶子 *)
 IF bottleSensor THEN
Pump_Motor := TRUE;
State := 1;
 END_IF;
1: (* 清洗 *)
 IF cleaningConfirmButton THEN
Pump_Motor := FALSE;
Filling_Valve := TRUE;
State := 2;
 END_IF;
2: (* 灌装 *)
 IF fillingConfirmButton THEN
Filling_Valve := FALSE;
Capping_Machine := TRUE;
State := 3;
 END_IF;
3: (* 封盖 *)
 IF cappingConfirmButton THEN
Capping_Machine := FALSE;
Packing_Machine := TRUE;
State := 4;
 END_IF;
4: (* 包装 *)
 IF packingConfirmButton THEN
Packing_Machine := FALSE;
Completion_Light := TRUE;
State := 5;
 END_IF;
5: (* 完成 *)
 IF finishedButton THEN
Completion_Light := FALSE;
