    previousValveBStart : BOOL := FALSE;
    previousValveCStart : BOOL := FALSE;
    previousValveDStart : BOOL := FALSE;
    previousMixMotorStart : BOOL := FALSE;
    previousAutoStart : BOOL := FALSE;

    (* Automatic mode state machine *)
    autoState : INT := 0; (* 0: Idle, 1: Valve A Open, 2: Valve B Open, 3: Process Mode Check, 4: Valve C Open, 5: Mixing, 6: Valve D Open *)
    autoActive : BOOL := FALSE;
END_VAR

(* Emergency Stop Logic - Highest Priority *)
IF NOT estop THEN
    (* Emergency stop triggered - stop all equipment *)
    valveARun := FALSE;
    valveBRun := FALSE;
    valveCRun := FALSE;
    valveDRun := FALSE;
    mixMotorRun := FALSE;
    autoActive := FALSE;
    autoState := 0;
ELSE
    (* Normal operation *)
    IF NOT opeMode THEN
        (* Manual Mode *)
        autoActive := FALSE;
        autoState := 0;

        (* Valve A toggle logic *)
        IF valveAStart AND NOT previousValveAStart THEN
            valveARun := NOT valveARun;
        END_IF;

        (* Valve B toggle logic *)
        IF valveBStart AND NOT previousValveBStart THEN
            valveBRun := NOT valveBRun;
        END_IF;

        (* Valve C toggle logic *)
        IF valveCStart AND NOT previousValveCStart THEN
            valveCRun := NOT valveCRun;
        END_IF;

        (* Valve D toggle logic *)
        IF valveDStart AND NOT previousValveDStart THEN
            valveDRun := NOT valveDRun;
        END_IF;

        (* Mixing Motor toggle logic *)
        IF mixMotorStart AND NOT previousMixMotorStart THEN
            mixMotorRun := NOT mixMotorRun;
        END_IF;

    ELSE
        (* Automatic Mode *)
        (* Auto start button detection *)
        IF autoStart AND NOT previousAutoStart AND NOT autoActive THEN
            autoActive := TRUE;
            autoState := 1; (* Start with Valve A *)
        END_IF;

        IF autoActive THEN
            CASE autoState OF
                1: (* Valve A Open *)
                    valveARun := TRUE;
                    valveBRun := FALSE;
                    valveCRun := FALSE;
                    valveDRun := FALSE;
                    mixMotorRun := FALSE;

                    IF levelSensor >= 50 THEN
                        autoState := 2; (* Move to Valve B *)
