                    valveCRun := TRUE;

                    IF levelSensor >= 100 THEN
                        valveCRun := FALSE;
                        autoState := 5; (* Move to mixing *)
                    END_IF;

                5: (* Mixing *)
                    mixMotorRun := TRUE;

                    IF mixMotorComplete THEN
                        mixMotorRun := FALSE;
                        autoState := 6; (* Move to Valve D *)
                    END_IF;

                6: (* Valve D Open - Final step *)
                    valveDRun := TRUE;
                    autoActive := FALSE; (* Process complete *)
                    autoState := 0; (* Return to idle *)

            END_CASE;
        ELSE
            (* Automatic mode not active - ensure all outputs are off *)
            valveARun := FALSE;
            valveBRun := FALSE;
            valveCRun := FALSE;
            valveDRun := FALSE;
            mixMotorRun := FALSE;
        END_IF;
    END_IF;
END_IF;

(* Store previous values for edge detection *)
previousValveAStart := valveAStart;
previousValveBStart := valveBStart;
previousValveCStart := valveCStart;
previousValveDStart := valveDStart;
previousMixMotorStart := mixMotorStart;
previousAutoStart := autoStart;

