FUNCTION_BLOCK TruckGarage
VAR_INPUT
    enter_flag : BOOL;
    exit_flag : BOOL;
    VehicleNumber_in : INT;
END_VAR

VAR_OUTPUT
    truck : T_TRUCK_INFO;
END_VAR

VAR_IN_OUT
    garage : ARRAY[1..3, 1..5] OF T_GARAGE_SLOT;
END_VAR

VAR
    i : INT;
    j : INT;
    entry_processed : BOOL;
    exit_processed : BOOL;
END_VAR

// Initialize output
truck.row := 0;
truck.col := 0;
truck.VehicleNumber := 0;

// Reset processing flags on falling edges
IF NOT enter_flag THEN
    entry_processed := FALSE;
END_IF;

IF NOT exit_flag THEN
    exit_processed := FALSE;
END_IF;

// Entry logic - process on rising edge of enter_flag
IF enter_flag AND NOT entry_processed THEN
    entry_processed := TRUE;

    // Search for empty slot using "latter row first, latter column first" principle
    FOR i := 3 TO 1 BY -1 DO
        FOR j := 5 TO 1 BY -1 DO
            IF NOT garage[i, j].Occupied THEN
                // Found empty slot - allocate it
                garage[i, j].Occupied := TRUE;
                garage[i, j].VehicleNumber := VehicleNumber_in;
                EXIT; // Exit inner loop
            END_IF;
        END_FOR;

        // Check if we found a slot in this row
        IF garage[i, j].Occupied AND garage[i, j].VehicleNumber = VehicleNumber_in THEN
            EXIT; // Exit outer loop
        END_IF;
    END_FOR;
END_IF;

// Exit logic - process on rising edge of exit_flag
IF exit_flag AND NOT exit_processed THEN
    exit_processed := TRUE;

    // Search for occupied slot using "former row first, former column first" principle
    FOR i := 1 TO 3 DO
        FOR j := 1 TO 5 DO
            IF garage[i, j].Occupied THEN
                // Found occupied slot - release it
                truck.row := i;
                truck.col := j;
                truck.VehicleNumber := garage[i, j].VehicleNumber;

                garage[i, j].Occupied := FALSE;
                garage[i, j].VehicleNumber := 0;
                EXIT; // Exit inner loop
            END_IF;
        END_FOR;

        // Check if we found and processed a slot
        IF truck.VehicleNumber <> 0 THEN
            EXIT; // Exit outer loop
        END_IF;
    END_FOR;
END_IF;
