FUNCTION_BLOCK FB_MergeBytes
VAR_INPUT
    byteArray : ARRAY[1..20] OF DINT; (* Byte array to be merged *)
END_VAR
VAR_OUTPUT
    dwordArray : ARRAY[1..10] OF DINT; (* Merged double word array *)
    mergeDwordNum : DINT; (* Actual number of merged double words *)
END_VAR
VAR
    i, j : INT;
    tempDword : DINT;
    byteIndex : INT;
    maxPossibleMerges : INT;
END_VAR
VAR CONSTANT
    BYTE_ARRAY_SIZE : DINT := 20; (* Size of the input byte array *)
    DWORD_ARRAY_SIZE : DINT := 10; (* Size of the output DINT array *)
    BYTES_PER_DWORD : INT := 4; (* Number of bytes per DWORD *)
END_VAR

(* Initialize output *)
mergeDwordNum := 0;
FOR i := 1 TO DWORD_ARRAY_SIZE DO
    dwordArray[i] := 0;
END_FOR;

(* Calculate maximum possible merges based on array sizes *)
maxPossibleMerges := MIN(BYTE_ARRAY_SIZE / BYTES_PER_DWORD, DWORD_ARRAY_SIZE);

(* Merge bytes into double words *)
FOR i := 1 TO maxPossibleMerges DO
    tempDword := 0;

    (* Merge 4 bytes into one DWORD *)
    FOR j := 0 TO BYTES_PER_DWORD-1 DO
        byteIndex := (i-1) * BYTES_PER_DWORD + j + 1;

        (* Ensure we don't exceed byteArray bounds *)
        IF byteIndex <= BYTE_ARRAY_SIZE THEN
            (* Shift byte to correct position and merge *)
            tempDword := tempDword OR (SHL(byteArray[byteIndex] AND 16#FF, j*8));
        END_IF;
    END_FOR;

    (* Store the merged DWORD *)
    dwordArray[i] := tempDword;
    mergeDwordNum := mergeDwordNum + 1;
END_FOR;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_LinearizeValue
VAR_INPUT
    InputValue : REAL; // Floating point input, raw measurement value
END_VAR

VAR_OUTPUT
    LinearizedValue : REAL; // Converted linear value
    Error : BOOL; // Error status indicator
    Status : WORD; // Status code
END_VAR

VAR
    // Internal constants for range boundaries
    MIN_INPUT : REAL := 1200.0;
    MAX_INPUT : REAL := 7000.0;

    // Range 1 boundaries
    R1_IN_MIN : REAL := 1200.0;
    R1_IN_MAX : REAL := 3600.0;
    R1_OUT_MIN : REAL := 150.0;
    R1_OUT_MAX : REAL := 240.0;

    // Range 2 boundaries
    R2_IN_MIN : REAL := 3600.0;
    R2_IN_MAX : REAL := 4800.0;
    R2_OUT_MIN : REAL := 240.0;
    R2_OUT_MAX : REAL := 560.0;

    // Range 3 boundaries
    R3_IN_MIN : REAL := 4800.0;
    R3_IN_MAX : REAL := 7000.0;
    R3_OUT_MIN : REAL := 560.0;
    R3_OUT_MAX : REAL := 720.0;
END_VAR

// Main execution logic
IF InputValue < MIN_INPUT THEN
    // Below minimum range
    LinearizedValue := R1_OUT_MIN; // 150.0
    Error := TRUE;
    Status := 16#8001;

ELSIF InputValue > MAX_INPUT THEN
    // Above maximum range
    LinearizedValue := R3_OUT_MAX; // 720.0
    Error := TRUE;
    Status := 16#8001;

ELSIF (InputValue >= R1_IN_MIN) AND (InputValue <= R1_IN_MAX) THEN
    // Range 1: 1200 to 3600
    LinearizedValue := R1_OUT_MIN + (InputValue - R1_IN_MIN) * 
                      (R1_OUT_MAX - R1_OUT_MIN) / (R1_IN_MAX - R1_IN_MIN);
    Error := FALSE;
    Status := 16#0000;

ELSIF (InputValue >= R2_IN_MIN) AND (InputValue <= R2_IN_MAX) THEN
    // Range 2: 3600 to 4800
    LinearizedValue := R2_OUT_MIN + (InputValue - R2_IN_MIN) * 
                      (R2_OUT_MAX - R2_OUT_MIN) / (R2_IN_MAX - R2_IN_MIN);
    Error := FALSE;
    Status := 16#0000;

ELSIF (InputValue >= R3_IN_MIN) AND (InputValue <= R3_IN_MAX) THEN
    // Range 3: 4800 to 7000
    LinearizedValue := R3_OUT_MIN + (InputValue - R3_IN_MIN) * 
                      (R3_OUT_MAX - R3_OUT_MIN) / (R3_IN_MAX - R3_IN_MIN);
    Error := FALSE;
    Status := 16#0000;

ELSE
    // This should not happen with the given ranges, but included for completeness
    LinearizedValue := 0.0;
    Error := TRUE;
    Status := 16#8001;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_WarehouseManagement
VAR_INPUT
    requestIn : BOOL := FALSE;
    requestOut : BOOL := FALSE;
END_VAR

VAR_OUTPUT
    productNum : INT := 0;
    libFreeNum : INT := 9;
    error : BOOL := FALSE;
    status : WORD := 16#0000;
END_VAR

VAR_IN_OUT
    library : ARRAY[1..9] OF BOOL;
END_VAR

VAR
    i : INT;
    found : BOOL;
    initDone : BOOL := FALSE;
END_VAR

(* Main execution block *)
(* Reset error status at start of each cycle *)
error := FALSE;
status := 16#0000;

(* Initialize library array if not done yet *)
IF NOT initDone THEN
    i := 1;
    WHILE i <= 9 DO
        library[i] := FALSE;
        i := i + 1;
    END_WHILE;
    initDone := TRUE;
END_IF;

(* Handle product storage request *)
IF requestIn AND NOT requestOut THEN
    (* Check if storage is full *)
    IF productNum >= 9 THEN
        error := TRUE;
        status := 16#8001;  (* Storage full error *)
    ELSE
        (* Search for free position from highest to lowest index *)
        i := 9;
        found := FALSE;
        WHILE i >= 1 AND NOT found DO
            IF NOT library[i] THEN
                library[i] := TRUE;  (* Mark position as occupied *)
                productNum := productNum + 1;
                libFreeNum := libFreeNum - 1;
                found := TRUE;
            END_IF;
            i := i - 1;
        END_WHILE;

        (* If no free position found despite productNum < 9, set error *)
        IF NOT found THEN
            error := TRUE;
            status := 16#8001;  (* Storage full error *)
        END_IF;
    END_IF;
END_IF;

(* Handle product retrieval request *)
IF requestOut AND NOT requestIn THEN
    (* Check if storage is empty *)
    IF productNum <= 0 THEN
        error := TRUE;
        status := 16#8002;  (* Storage empty error *)
    ELSE
        (* Search for occupied position from lowest to highest index *)
        i := 1;
        found := FALSE;
        WHILE i <= 9 AND NOT found DO
            IF library[i] THEN
                library[i] := FALSE;  (* Mark position as available *)
                productNum := productNum - 1;
                libFreeNum := libFreeNum + 1;
                found := TRUE;
            END_IF;
            i := i + 1;
        END_WHILE;

        (* If no occupied position found despite productNum > 0, set error *)
        IF NOT found THEN
            error := TRUE;
            status := 16#8002;  (* Storage empty error *)
        END_IF;
    END_IF;
END_IF;

(* Handle concurrent requests - prioritize retrieval over storage *)
IF requestIn AND requestOut THEN
    (* First try retrieval *)
    IF productNum > 0 THEN
        i := 1;
        found := FALSE;
        WHILE i <= 9 AND NOT found DO
            IF library[i] THEN
                library[i] := FALSE;
                productNum := productNum - 1;
                libFreeNum := libFreeNum + 1;
                found := TRUE;
            END_IF;
            i := i + 1;
        END_WHILE;

        IF NOT found AND productNum > 0 THEN
            error := TRUE;
            status := 16#8002;
        END_IF;
    ELSE
        error := TRUE;
        status := 16#8002;
    END_IF;

    (* Then try storage if retrieval was successful *)
    IF NOT error AND productNum < 9 THEN
        i := 9;
        found := FALSE;
        WHILE i >= 1 AND NOT found DO
            IF NOT library[i] THEN
                library[i] := TRUE;
                productNum := productNum + 1;
                libFreeNum := libFreeNum - 1;
                found := TRUE;
            END_IF;
            i := i - 1;
        END_WHILE;

        IF NOT found AND productNum < 9 THEN
            error := TRUE;
            status := 16#8001;
        END_IF;
    ELSIF NOT error AND productNum >= 9 THEN
        error := TRUE;
        status := 16#8001;
    END_IF;
END_IF;

(* Validate counters consistency *)
IF (productNum + libFreeNum) <> 9 THEN
    (* This should never happen, but added for safety *)
    error := TRUE;
    status := 16#8003;  (* Internal consistency error *)
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_ColorLightControl
{ S7_Optimized_Access := 'TRUE' }
VAR_INPUT 
    controlButton : BOOL; // Push button for sequence control
END_VAR

VAR_OUTPUT 
    greenLight : BOOL; // Green light control signal
    redLight : BOOL; // Red light control signal
    yellowLight : BOOL; // Yellow light control signal
END_VAR

VAR 
    state : INT := 1; // State machine control variable
    lastControlButton : BOOL := FALSE; // Previous button state
    buttonRisingEdge : BOOL; // Rising edge detection flag
END_VAR

// Rising edge detection for control button
buttonRisingEdge := controlButton AND NOT lastControlButton;

// State machine execution on rising edge
IF buttonRisingEdge THEN
    // Execute state transition
    state := state + 1;
    IF state > 5 THEN
        state := 1;
    END_IF;
END_IF;

// Update light outputs based on current state
CASE state OF
    1: // State 1: Green Only
        greenLight := TRUE;
        redLight := FALSE;
        yellowLight := FALSE;

    2: // State 2: Red Only
        greenLight := FALSE;
        redLight := TRUE;
        yellowLight := FALSE;

    3: // State 3: Yellow Only
        greenLight := FALSE;
        redLight := FALSE;
        yellowLight := TRUE;

    4: // State 4: All Lights On
        greenLight := TRUE;
        redLight := TRUE;
        yellowLight := TRUE;

    5: // State 5: All Lights Off
        greenLight := FALSE;
        redLight := FALSE;
        yellowLight := FALSE;

    ELSE // Fallback to State 1 (should not occur)
        state := 1;
        greenLight := TRUE;
        redLight := FALSE;
        yellowLight := FALSE;
END_CASE;

// Store current button state for next cycle
lastControlButton := controlButton;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_DatabaseManager
VAR_INPUT
    dataInput : ARRAY[0..5] OF BYTE;
    storeTrigger : BOOL;
    resetTrigger : BOOL;
END_VAR

VAR_OUTPUT
    usedSpace : INT := 0;
    remainingSpace : INT := 20;
    error : BOOL;
    status : WORD;
END_VAR

VAR_IN_OUT
    dataBase : ARRAY[1..20] OF BYTE;
END_VAR

VAR
    i : INT;
    dataLength : INT;
END_VAR

// Main execution logic
IF resetTrigger THEN
    // Reset operation
    FOR i := 1 TO 20 DO
        dataBase[i] := 0;
    END_FOR;

    usedSpace := 0;
    remainingSpace := 20;
    error := FALSE;
    status := 0;

ELSIF storeTrigger AND NOT resetTrigger THEN
    // Data storage operation
    dataLength := dataInput[0];

    // Length validation
    IF (dataLength <= 0) OR (dataLength > 5) THEN
        error := TRUE;
        status := 16#8001;
    ELSE
        // Space verification
        IF (usedSpace + dataLength) > 20 THEN
            error := TRUE;
            status := 16#8002;
        ELSE
            // Data storage
            FOR i := 1 TO dataLength DO
                dataBase[usedSpace + i] := dataInput[i];
            END_FOR;

            // Update counters
            usedSpace := usedSpace + dataLength;
            remainingSpace := 20 - usedSpace;

            // Set success status
            error := FALSE;
            status := 0;
        END_IF;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_ProductionLineControl
VAR_INPUT
    Mode : BOOL;            // Manual/Auto mode selection
    ForwardButton : BOOL;   // Forward rotation button
    ReverseButton : BOOL;   // Reverse rotation button
