    MotorReverse : BOOL;    // Motor reverse output
    CompletionLight : BOOL; // Process completion indicator
END_VAR

VAR
    State : INT := 0;       // State machine current state
END_VAR

// Main execution logic
CASE State OF
    0: // Initialization state
        MotorForward := FALSE;
        MotorReverse := FALSE;
        CompletionLight := FALSE;
        State := 1;

    1: // State 1 - Mode selection and Station A waiting
        IF NOT Mode THEN // Manual mode
            // Manual motor control with mutual exclusion
            IF ForwardButton AND NOT ReverseButton THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
            ELSIF ReverseButton AND NOT ForwardButton THEN
                MotorForward := FALSE;
                MotorReverse := TRUE;
            ELSE // Both pressed or neither pressed
                MotorForward := FALSE;
                MotorReverse := FALSE;
            END_IF;
            CompletionLight := FALSE;
        ELSE // Automatic mode
            MotorForward := FALSE;
            MotorReverse := FALSE;
            CompletionLight := FALSE;

            // Wait for SensorA activation
            IF SensorA THEN
                State := 2; // Transition to Station A processing
            END_IF;
        END_IF;

    2: // State 2 - Processing at Station A (Automatic mode only)
        IF NOT Mode THEN
            State := 1; // Return to manual mode handling
        ELSE
            // Wait for ButtonA press
            IF ButtonA THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
                State := 3; // Transition to moving to Station B
            END_IF;
        END_IF;

    3: // State 3 - Moving to Station B (Automatic mode only)
        IF NOT Mode THEN
            MotorForward := FALSE;
            MotorReverse := FALSE;
            State := 1; // Return to manual mode handling
        ELSE
            // Wait for SensorB activation
            IF SensorB THEN
                MotorForward := FALSE;
                State := 4; // Transition to Station B processing
            END_IF;
        END_IF;

    4: // State 4 - Processing at Station B (Automatic mode only)
        IF NOT Mode THEN
            State := 1; // Return to manual mode handling
        ELSE
            // Wait for ButtonB press
            IF ButtonB THEN
                MotorForward := TRUE;
                MotorReverse := FALSE;
                State := 5; // Transition to moving to Station C
            END_IF;
        END_IF;

    5: // State 5 - Moving to Station C (Automatic mode only)
        IF NOT Mode THEN
            MotorForward := FALSE;
            MotorReverse := FALSE;
            State := 1; // Return to manual mode handling
        ELSE
            // Wait for SensorC activation
            IF SensorC THEN
                MotorForward := FALSE;
                State := 6; // Transition to Station C processing
            END_IF;
        END_IF;

    6: // State 6 - Processing at Station C (Automatic mode only)
        IF NOT Mode THEN
            State := 1; // Return to manual mode handling
        ELSE
            // Wait for ButtonC press
            IF ButtonC THEN
                CompletionLight := TRUE;
                State := 7; // Transition to cycle completion
            END_IF;
        END_IF;

    7: // State 7 - Cycle Completion (Automatic mode only)
        IF NOT Mode THEN
            CompletionLight := FALSE;
            State := 1; // Return to manual mode handling
        ELSE
            // Wait for product removal (SensorC deactivation)
            IF NOT SensorC THEN
                CompletionLight := FALSE;
                State := 1; // Return to start of automatic cycle
            END_IF;
        END_IF;

    ELSE // Error state handling
        MotorForward := FALSE;
        MotorReverse := FALSE;
        CompletionLight := FALSE;
        State := 0; // Reset to initialization
END_CASE;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_SplitNumber
VAR_INPUT
    InputNumber : INT;
END_VAR

VAR_OUTPUT
    Thousands : INT;
    Hundreds : INT;
    Tens : INT;
    Ones : INT;
    Min : INT;
    error : BOOL;
    status : WORD;
END_VAR

VAR
    tempNumber : INT;
    minValue : INT;
END_VAR

(* Input Validation *)
IF (InputNumber < 0) OR (InputNumber > 9999) THEN
    (* Error condition - Input out of range *)
    error := TRUE;
    status := 16#8001;

    (* Reset all outputs *)
    Thousands := 0;
    Hundreds := 0;
    Tens := 0;
    Ones := 0;
    Min := 0;
ELSE
    (* Valid input - proceed with processing *)
    error := FALSE;
    status := 16#0000;

    (* Digit separation using division and modulo operations *)
    Thousands := InputNumber / 1000;
    tempNumber := InputNumber MOD 1000;
    Hundreds := tempNumber / 100;
    tempNumber := tempNumber MOD 100;
    Tens := tempNumber / 10;
    Ones := tempNumber MOD 10;

    (* Minimum non-zero digit detection *)
    minValue := 32767; (* Initialize with maximum INT value *)

    (* Check Thousands digit *)
    IF Thousands > 0 THEN
        minValue := minimal(Thousands, minValue);
    END_IF;

    (* Check Hundreds digit *)
    IF Hundreds > 0 THEN
        minValue := minimal(Hundreds, minValue);
    END_IF;

    (* Check Tens digit *)
    IF Tens > 0 THEN
        minValue := minimal(Tens, minValue);
    END_IF;

    (* Check Ones digit *)
    IF Ones > 0 THEN
        minValue := minimal(Ones, minValue);
    END_IF;

    (* Set Min output *)
    IF minValue = 32767 THEN
        (* All digits are zero *)
        Min := 0;
    ELSE
        Min := minValue;
    END_IF;
END_IF;

END_FUNCTION_BLOCK

