FUNCTION_BLOCK CoffeeMachineControl
VAR_INPUT
    StartButton : BOOL;
    ElapsedTime : DINT; (* Time elapsed since the start of the current process, in milliseconds *)
END_VAR

VAR_OUTPUT
    WaterHeating : BOOL;
    GrinderRunning : BOOL;
    Brewing : BOOL;
    GrinderFinished : BOOL;
    WaterHeated : BOOL;
    CoffeeReady : BOOL;
END_VAR

VAR
    WaterHeatingDuration : DINT := 30000; (* 30 seconds in milliseconds *)
    GrinderDuration : DINT := 15000; (* 15 seconds in milliseconds *)
    BrewingDuration : DINT := 60000; (* 60 seconds in milliseconds *)

    (* Internal state machine *)
    CurrentState : INT := 0;
    ProcessStartTime : DINT := 0;

    (* Internal flags *)
    InternalWaterHeated : BOOL := FALSE;
    InternalGrinderFinished : BOOL := FALSE;
    InternalCoffeeReady : BOOL := FALSE;
END_VAR

(* State machine implementation *)
CASE CurrentState OF
    0: (* IDLE state - waiting for start button *)
        WaterHeating := FALSE;
        GrinderRunning := FALSE;
        Brewing := FALSE;
        WaterHeated := FALSE;
        GrinderFinished := FALSE;
        CoffeeReady := FALSE;
        InternalWaterHeated := FALSE;
        InternalGrinderFinished := FALSE;
        InternalCoffeeReady := FALSE;

        IF StartButton THEN
            CurrentState := 1; (* Move to water heating state *)
            ProcessStartTime := ElapsedTime;
        END_IF;

    1: (* WATER HEATING state *)
        WaterHeating := TRUE;
        GrinderRunning := FALSE;
        Brewing := FALSE;

        (* Check if water heating duration has elapsed *)
        IF (ElapsedTime - ProcessStartTime) >= WaterHeatingDuration THEN
            WaterHeated := TRUE;
            InternalWaterHeated := TRUE;
            WaterHeating := FALSE;
            CurrentState := 2; (* Move to grinding state *)
            ProcessStartTime := ElapsedTime;
        ELSE
            WaterHeated := FALSE;
        END_IF;

    2: (* GRINDING state *)
        WaterHeating := FALSE;
        GrinderRunning := TRUE;
        Brewing := FALSE;

        (* Check if grinding duration has elapsed *)
        IF (ElapsedTime - ProcessStartTime) >= GrinderDuration THEN
            GrinderFinished := TRUE;
            InternalGrinderFinished := TRUE;
            GrinderRunning := FALSE;
            CurrentState := 3; (* Move to brewing state *)
            ProcessStartTime := ElapsedTime;
        ELSE
            GrinderFinished := FALSE;
        END_IF;

    3: (* BREWING state *)
        WaterHeating := FALSE;
        GrinderRunning := FALSE;
        Brewing := TRUE;

        (* Check if brewing duration has elapsed *)
        IF (ElapsedTime - ProcessStartTime) >= BrewingDuration THEN
            CoffeeReady := TRUE;
            InternalCoffeeReady := TRUE;
            Brewing := FALSE;
            CurrentState := 4; (* Move to finished state *)
        ELSE
            CoffeeReady := FALSE;
        END_IF;

    4: (* FINISHED state - maintain outputs until reset *)
        WaterHeating := FALSE;
        GrinderRunning := FALSE;
        Brewing := FALSE;
        WaterHeated := InternalWaterHeated;
        GrinderFinished := InternalGrinderFinished;
        CoffeeReady := InternalCoffeeReady;

        (* Reset when start button is released *)
        IF NOT StartButton THEN
            CurrentState := 0;
        END_IF;

    ELSE
        (* Error state - reset to IDLE *)
        CurrentState := 0;
END_CASE;

(* Ensure outputs are reset when start button is not pressed and not in finished state *)
IF NOT StartButton AND CurrentState <> 4 THEN
    CurrentState := 0;
END_IF;

END_FUNCTION_BLOCK

