        DoughRollerMotor := FALSE;
        ToppingDispenser := FALSE;
        ConveyorMotor := FALSE;
        OvenHeater := FALSE;
        OvenTemperature := 0;

        (* Start process when start button pressed and stop button not engaged *)
        IF StartButton AND NOT StopButton THEN
            bProcessActive := TRUE;
            eCurrentState := DOUGH_PREP;
        END_IF;

    DOUGH_PREP:
        (* Activate dough roller if dough not ready *)
        IF NOT DoughReadySensor THEN
            DoughRollerMotor := TRUE;
            ToppingDispenser := FALSE;
            ConveyorMotor := FALSE;
        ELSE
            DoughRollerMotor := FALSE;
            eCurrentState := TOPPING_DISPENSE;
        END_IF;

        (* Emergency stop check *)
        IF StopButton THEN
            eCurrentState := IDLE;
            bProcessActive := FALSE;
        END_IF;

    TOPPING_DISPENSE:
        (* Activate topping dispenser if toppings not ready *)
        IF NOT ToppingsReadySensor THEN
            ToppingDispenser := TRUE;
            DoughRollerMotor := FALSE;
            ConveyorMotor := FALSE;
        ELSE
