            eCurrentState := CONVEY_TO_OVEN;
        END_IF;

        (* Emergency stop check *)
        IF StopButton THEN
            eCurrentState := IDLE;
            bProcessActive := FALSE;
        END_IF;

    CONVEY_TO_OVEN:
        (* Move pizza to oven when both dough and toppings are ready *)
        IF DoughReadySensor AND ToppingsReadySensor THEN
            ConveyorMotor := TRUE;
            DoughRollerMotor := FALSE;
            ToppingDispenser := FALSE;
            eCurrentState := BAKING;
        END_IF;

        (* Emergency stop check *)
        IF StopButton THEN
            eCurrentState := IDLE;
            bProcessActive := FALSE;
        END_IF;

    BAKING:
        (* Start baking process *)
        ConveyorMotor := FALSE;
        bBakingInProgress := TRUE;
        OvenHeater := TRUE;
        OvenTemperature := 220;  (* Set to 220°C *)

        (* Check if baking is complete *)
