    NutrientThreshold : REAL := 0.7;  (* Nutrient level threshold for analysis *)
    pHThreshold : REAL := 6.5;        (* pH level threshold for analysis *)
END_VAR

(* Main execution logic *)
IF TestingStatus = 0 THEN (* Idle State *)
    (* Initialize sensor values *)
    pHSensorValue := 7.0;
    NutrientSensorValue := 0.5;

    (* Check for start command *)
    IF StartButton THEN
        TestingStatus := 1; (* Transition to Testing state *)
        NutrientPump := TRUE;
        pHAdjustmentPump := TRUE;
    ELSE
        NutrientPump := FALSE;
        pHAdjustmentPump := FALSE;
    END_IF;

ELSIF TestingStatus = 1 THEN (* Testing State *)
    (* Update simulated sensor values during testing *)
    NutrientSensorValue := LIMIT(0.5, NutrientSensorValue + 0.1, 0.9);
    pHSensorValue := LIMIT(4.0, pHSensorValue - 0.5, 7.0);

    (* Check for sample detection and analysis *)
    IF SoilSampleDetected THEN
        IF (NutrientSensorValue >= NutrientThreshold) AND (pHSensorValue <= pHThreshold) THEN
            TestingStatus := 2; (* Transition to Completed state *)
            NutrientPump := FALSE;
            pHAdjustmentPump := FALSE;
        END_IF;
    END_IF;

ELSIF TestingStatus = 2 THEN (* Completed State *)
    (* Keep pumps deactivated in completed state *)
    NutrientPump := FALSE;
    pHAdjustmentPump := FALSE;

    (* Option: Add logic to reset to idle if needed *)
